import React, { useEffect, useState, useCallback } from "react";
import axios from "axios";

const TimbangMuat = () => {
  const [truck, setTruck] = useState(null);
  const [list, setList] = useState([]);

  // mode:
  const [step, setStep] = useState("BRUTO"); 
  // BRUTO / TARA

  const [form, setForm] = useState({
    itemType: "",
    no_palka: "",
    bruto_belawan: "",
    tara_belawan: "",
  });

  // ================= RFID =================
  const fetchRFID = useCallback(async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/rfid/latest");
      const truckData = res.data?.truck;

      if (truckData?.truckId) {
        setTruck(truckData);
        fetchData(truckData.truckId);
      } else {
        setTruck(null);
      }
    } catch (err) {
      console.error(err);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (!truck) fetchRFID();
    }, 2000);

    return () => clearInterval(interval);
  }, [truck, fetchRFID]);

  // ================= INPUT =================
  const handleChange = (e) => {
    setForm((p) => ({
      ...p,
      [e.target.name]: e.target.value,
    }));
  };

  // ================= SUBMIT BRUTO =================
  const submitBruto = async () => {
    const payload = {
      truckId: truck.truckId,
      itemType: form.itemType,
      no_palka: form.no_palka,
      bruto_belawan: Number(form.bruto_belawan),
      unit: "kg",
    };

    await axios.post("http://localhost:5000/api/loadings", payload);

    setStep("TARA");
    fetchData(truck.truckId);
  };

  // ================= SUBMIT TARA =================
  const submitTara = async () => {
    const payload = {
      tara_belawan: Number(form.tara_belawan),
    };

    await axios.put(
      `http://localhost:5000/api/loadings/tara/${truck.truckId}`,
      payload
    );

    alert("Tara berhasil disimpan");

    setForm({
      itemType: "",
      no_palka: "",
      bruto_belawan: "",
      tara_belawan: "",
    });

    setStep("BRUTO");
    fetchData(truck.truckId);
  };

  // ================= FETCH DATA =================
  const fetchData = async (truckId) => {
    const res = await axios.get(
      `http://localhost:5000/api/loadings/${truckId}`
    );
    setList(res.data || []);
  };

  // ================= UI =================
  return (
    <div style={{ padding: 20 }}>
      <h2>Timbang Muat</h2>

      {!truck && <p>Menunggu RFID...</p>}

      {truck && (
        <>
          <h3>Truck: {truck.truckId}</h3>

          {/* STEP 1: BRUTO */}
          {step === "BRUTO" && (
            <div>
              <input
                name="itemType"
                placeholder="Item"
                onChange={handleChange}
              />
              <input
                name="no_palka"
                placeholder="No Palka"
                onChange={handleChange}
              />
              <input
                name="bruto_belawan"
                placeholder="Bruto"
                type="number"
                onChange={handleChange}
              />

              <button onClick={submitBruto}>
                Simpan Bruto
              </button>
            </div>
          )}

          {/* STEP 2: TARA */}
          {step === "TARA" && (
            <div>
              <input
                name="tara_belawan"
                placeholder="Tara"
                type="number"
                onChange={handleChange}
              />

              <button onClick={submitTara}>
                Simpan Tara
              </button>
            </div>
          )}

          {/* TABLE */}
          <table border="1" style={{ marginTop: 20 }}>
            <thead>
              <tr>
                <th>Item</th>
                <th>No Palka</th>
                <th>Bruto</th>
                <th>Tara</th>
                <th>Netto</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {list.map((x) => (
                <tr key={x.id}>
                  <td>{x.itemType}</td>
                  <td>{x.no_palka}</td>
                  <td>{x.bruto_belawan}</td>
                  <td>{x.tara_belawan}</td>
                  <td>{x.netto_belawan}</td>
                  <td>{x.status_timbang}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </>
      )}
    </div>
  );
};

export default TimbangMuat;
